1	interface QuoteItem {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: QuoteItem[];
8	}
9	
10	interface Scenario {
11	  customer: { yearsWithMHPCO: number };
12	  steps: QuoteStep[];
13	}
14	
15	const BASE_PREMIUM: Record<string, number> = {
16	  amulet: 60,
17	};
18	
19	const FIRST_INSURANCE_RATE = 0.1;
20	const PROCESSING_FEE = 5;
21	
22	export function runScenario(scenario: Scenario): {
23	  results: { premium: number }[];
24	} {
25	  const results = scenario.steps.map((step) => {
26	    const policyBase = step.items.reduce(
27	      (sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0),
28	      0,
29	    );
30	    const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
31	    const premium = Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
32	    return { premium };
33	  });
34	  return { results };
